                            </svg>
                            <span>{t('pin_lock.whatsapp')}</span>
                        </a>
                    </div>
                 </div>

            </div>

             {/* Activate Modal */}
             {showActivateModal && (
                <PinLockScreen 
                    onUnlock={(pin) => {
                        const success = onUnlock(pin);
                        if (success) setShowActivateModal(false);
                        return success;
                    }} 
                    deviceId={deviceId} 
                    onCancel={() => setShowActivateModal(false)}
                />
            )}
        </div>
    );
};

