            <p className="text-gray-400 text-sm font-medium">{title}</p>
            <p className="text-2xl font-bold text-white">{value}</p>
        </div>
    </div>
);

const QuickActionButton: React.FC<{ onClick: () => void; label: string; icon: React.ReactElement }> = ({ onClick, label, icon }) => (
    <button
        onClick={onClick}
        className="flex-1 bg-[#F7C873] text-[#0B132B] font-bold py-3 px-4 rounded-lg flex items-center justify-center hover:bg-yellow-400 transition-colors duration-200"
    >
        {icon}
        <span className="ms-2">{label}</span>
    </button>
);


const Dashboard: React.FC<DashboardProps> = ({ userName, orders, clients, setView, onAddNewOrder, onAddNewClient }) => {
    const { t, language } = useLanguage();
    const [scheduleView, setScheduleView] = useState<'today' | 'week'>('today');

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const todaysBookings = orders.filter(order => {
        const orderDate = new Date(order.dateTime);
        orderDate.setHours(0, 0, 0, 0);
        return orderDate.getTime() === today.getTime() && order.status === 'confirmed';
    });

    const upcomingBookings = orders.filter(order => new Date(order.dateTime) > new Date() && order.status === 'confirmed');

    // Updated Revenue Logic: 
    // 1. Include deposits for all non-cancelled orders in this month.
    // 2. Include full price for completed orders in this month.
    const totalRevenueThisMonth = orders
        .filter(order => 
            new Date(order.dateTime).getMonth() === new Date().getMonth() && 
            new Date(order.dateTime).getFullYear() === new Date().getFullYear() && 
            order.status !== 'cancelled'
        )
        .reduce((sum, order) => {
            // If completed, we take the full price. 
            // If not completed (pending/confirmed), we only take the deposit.
            const earnedFromThisOrder = order.status === 'completed' 
                ? order.priceAmount 
                : order.depositPaid;
            return sum + earnedFromThisOrder;
        }, 0);

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat(language === 'ar' ? 'ar-EG' : 'en-US', { style: 'currency', currency: 'EGP', minimumFractionDigits: 0 }).format(amount);
    }

    const getClientName = (clientId: string) => clients.find(c => c.id === clientId)?.name || t('common.unknown_client');

    const now = new Date();
    const todayForWeekCalc = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const dayOfWeek = todayForWeekCalc.getDay(); 
    const weekStartsOn = 6; 

    let dayOffset = dayOfWeek - weekStartsOn;
    if (dayOffset < 0) {
        dayOffset += 7;
    }

    const startOfWeek = new Date(todayForWeekCalc.getFullYear(), todayForWeekCalc.getMonth(), todayForWeekCalc.getDate() - dayOffset);
    const endOfWeek = new Date(startOfWeek.getFullYear(), startOfWeek.getMonth(), startOfWeek.getDate() + 6, 23, 59, 59, 999);

    const thisWeeksBookings = orders
        .filter(order => {
            const orderDate = new Date(order.dateTime);
            return orderDate >= startOfWeek && orderDate <= endOfWeek && order.status === 'confirmed';
        })
        .sort((a, b) => new Date(a.dateTime).getTime() - new Date(b.dateTime).getTime());

    const bookingsToShow = scheduleView === 'today' ? todaysBookings : thisWeeksBookings;
    const scheduleTitle = scheduleView === 'today' ? t('dashboard.todays_schedule') : t('dashboard.this_weeks_schedule');
    const noBookingsMessage = scheduleView === 'today' ? t('dashboard.no_bookings_today') : t('dashboard.no_bookings_this_week');

    const openInGoogleMaps = (lat: number, lng: number) => {
        const url = `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`;
        window.open(url, '_blank');
    };

    const handleAddToCalendar = (order: Order) => {
        const startDate = new Date(order.dateTime);
        const endDate = new Date(startDate.getTime() + (order.duration * 60000));

        // Helper to format date for ICS: YYYYMMDDTHHMMSSZ
        const formatICSDate = (date: Date) => {
             return date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
        };

        const client = clients.find(c => c.id === order.clientId);
        const description = `${t('orders.table.client')}: ${client?.name || ''}\\n${t('add_client.form.phone')}: ${client?.phone || ''}\\n${t('add_order.form.package_name')}: ${order.servicePackage.name}\\n${t('add_order.form.notes')}: ${order.notes || ''}`;

        const icsContent = `BEGIN:VCALENDAR
VERSION:2.0
PRODID:-//StudioPay//StudioPay App//EN
BEGIN:VEVENT
UID:${order.id}@studiopay.app
DTSTAMP:${formatICSDate(new Date())}
DTSTART:${formatICSDate(startDate)}
DTEND:${formatICSDate(endDate)}
SUMMARY:${order.title} - StudioPay
DESCRIPTION:${description}
LOCATION:${order.location.addressText || ''}
END:VEVENT
END:VCALENDAR`;

        const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', `event_${order.id}.ics`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div>
            <h1 className="text-3xl font-bold text-white mb-6">{t('dashboard.welcome', { name: userName })}</h1>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
                <StatCard title={t('dashboard.revenue_this_month')} value={formatCurrency(totalRevenueThisMonth)} color="border-green-400" icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v.01" /></svg>} />
                <StatCard title={t('dashboard.bookings_today')} value={todaysBookings.length} color="border-blue-400" icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>} />
                <StatCard title={t('dashboard.upcoming_bookings')} value={upcomingBookings.length} color="border-yellow-400" icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-yellow-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>} />
            </div>

            <div className="flex flex-col md:flex-row gap-6 mb-8">
                 <QuickActionButton onClick={onAddNewOrder} label={t('dashboard.add_new_booking')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>} />
                 <QuickActionButton onClick={onAddNewClient} label={t('dashboard.add_new_client')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" /></svg>} />
            </div>

            <div className="bg-[#1C2541] p-6 rounded-xl shadow-lg">
                <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                    <h2 className="text-xl font-bold text-white">{scheduleTitle}</h2>
                    <div className="flex bg-[#0B132B] p-1 rounded-lg self-start sm:self-center">
                        <button 
                            onClick={() => setScheduleView('today')}
                            className={`px-4 py-1 text-sm font-semibold rounded-md transition-colors ${scheduleView === 'today' ? 'bg-[#F7C873] text-[#0B132B]' : 'text-gray-400 hover:text-white'}`}
                        >
                            {t('dashboard.view_today')}
                        </button>
                        <button
                            onClick={() => setScheduleView('week')}
                            className={`px-4 py-1 text-sm font-semibold rounded-md transition-colors ${scheduleView === 'week' ? 'bg-[#F7C873] text-[#0B132B]' : 'text-gray-400 hover:text-white'}`}
                        >
                            {t('dashboard.view_week')}
                        </button>
                    </div>
                </div>
                {bookingsToShow.length > 0 ? (
                     <div className="space-y-4">
                        {bookingsToShow.map(order => (
                            <div key={order.id} className="bg-[#0B132B] p-4 rounded-lg flex justify-between items-center">
                                <div>
                                    <p className="font-bold text-lg text-white">{order.title}</p>
                                    <p className="text-sm text-gray-400">{getClientName(order.clientId)}</p>
                                </div>
                                <div className="text-end flex flex-col items-end">
                                    <p className="font-semibold text-yellow-400 mb-1">
                                        {scheduleView === 'week' 
                                            ? new Date(order.dateTime).toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', { weekday: 'short', hour: '2-digit', minute: '2-digit' })
                                            : new Date(order.dateTime).toLocaleTimeString(language === 'ar' ? 'ar-EG' : 'en-US', { hour: '2-digit', minute: '2-digit' })}
                                    </p>
                                    <div className="flex gap-3">
                                        <button 
                                            onClick={() => handleAddToCalendar(order)}
                                            className="text-xs text-blue-400 hover:text-blue-300 transition-colors flex items-center gap-1"
                                            title={t('common.add_to_calendar')}
                                        >
                                             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                                            </svg>
                                        </button>
                                        <button 
                                            onClick={() => openInGoogleMaps(order.location.lat, order.location.lng)}
                                            className="text-xs text-gray-500 hover:text-[#F7C873] transition-colors flex items-center gap-1"
                                        >
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                                            </svg>
                                            {order.location.addressText || t('map_picker.unknown_location')}
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-gray-400 text-center py-4">{noBookingsMessage}</p>
                )}
            </div>
        </div>
    );
}

export default Dashboard;

import React, { useRef, useState } from 'react';
import { useLanguage } from '../useLanguage';
import { Order } from '../types';
import PinLockScreen from './PinLockScreen';

interface SettingsProps {
    orders: Order[];
    onUnlock: (pin: string) => boolean;
    deviceId: string;
    notifyLeadTime: number;
    onSetNotifyLeadTime: (hours: number) => void;
}

const Settings: React.FC<SettingsProps> = ({ orders, onUnlock, deviceId, notifyLeadTime, onSetNotifyLeadTime }) => {
    const { t, language, setLanguage } = useLanguage();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [showActivateModal, setShowActivateModal] = useState(false);

    // Updated Links
    const FACEBOOK_PAGE_LINK = "https://www.facebook.com/share/19xnqWbbxh/?mibextid=wwXIfr"; 
    const WHATSAPP_LINK = "https://wa.me/201273044202";

    const handleExport = () => {
        // SECURITY UPDATE: We only export content data (Clients, Orders, Name).
        // We DO NOT export 'activationDate', 'firstUseTimestamp', or 'deviceId'.
        // This prevents users from sharing a backup file to activate the app on other devices for free.
        const dataToExport = {
            clients: localStorage.getItem('clients'),
            orders: localStorage.getItem('orders'),
            userName: localStorage.getItem('userName'),
            version: '1.2'
        };

        const blob = new Blob([JSON.stringify(dataToExport)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        const date = new Date().toISOString().slice(0, 10);
        a.download = `StudioPay_Backup_${date}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleImportClick = () => {
        fileInputRef.current?.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const result = event.target?.result;
                if (typeof result === 'string') {
                    const importedData = JSON.parse(result);

                    // SECURITY UPDATE: Only import content. Never overwrite subscription status.
                    if (importedData.clients) localStorage.setItem('clients', importedData.clients);
                    if (importedData.orders) localStorage.setItem('orders', importedData.orders);
                    if (importedData.userName) localStorage.setItem('userName', importedData.userName);

                    // Note: We intentionally do NOT import 'activationDate' or 'isActivated'.

                    alert(t('settings.success_import'));
                    window.location.reload();
                }
            } catch (error) {
                console.error("Import error", error);
                alert(t('settings.error_import'));
            }
        };
        reader.readAsText(file);
    };

    const handleReset = () => {
        if (window.confirm(t('settings.reset_confirm'))) {
            // Only clear content data, preserve subscription and settings
            localStorage.setItem('clients', '[]');
            localStorage.setItem('orders', '[]');
            // Force reload to reflect empty state
            window.location.reload();
        }
    };

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat(language === 'ar' ? 'ar-EG' : 'en-US', { style: 'currency', currency: 'EGP', minimumFractionDigits: 0 }).format(amount);
    }

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    }

    const getMonthlyRevenue = () => {
        const revenueMap: Record<string, number> = {};
        // Filter out cancelled orders.
        orders.filter(o => o.status !== 'cancelled').forEach(order => {
            const date = new Date(order.dateTime);
            const key = `${date.getFullYear()}-${date.getMonth()}`;

            // Logic: Count full price if completed, otherwise only the deposit.
            const earnedAmount = order.status === 'completed' 
                ? order.priceAmount 
                : order.depositPaid;

            revenueMap[key] = (revenueMap[key] || 0) + earnedAmount;
        });

        return Object.entries(revenueMap).map(([key, amount]) => {
            const [year, month] = key.split('-').map(Number);
            return {
                date: new Date(year, month, 1),
                amount
            };
        }).sort((a, b) => b.date.getTime() - a.date.getTime()); 
    };

    const monthlyRevenueHistory = getMonthlyRevenue();

    const activationDateStr = localStorage.getItem('activationDate');
    const firstUseStr = localStorage.getItem('firstUseTimestamp');

    let subscriptionStatus = 'trial';
    let daysLeft = 0;
    let startDateStr = '';
    let endDateStr = '';
    let progressPercent = 0;

    if (activationDateStr) {
        subscriptionStatus = 'active';
        const startDate = new Date(activationDateStr);
        const endDate = new Date(startDate);
        endDate.setDate(startDate.getDate() + 365);

        const now = new Date();
        const totalDuration = endDate.getTime() - startDate.getTime();
        const elapsed = now.getTime() - startDate.getTime();

        daysLeft = Math.ceil((endDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
        if (daysLeft < 0) daysLeft = 0;

        progressPercent = Math.min(100, Math.max(0, (elapsed / totalDuration) * 100));

        startDateStr = formatDate(activationDateStr);
        endDateStr = formatDate(endDate.toISOString());

    } else if (firstUseStr) {
        subscriptionStatus = 'trial';
        const daysPassed = (new Date().getTime() - new Date(firstUseStr).getTime()) / (1000 * 60 * 60 * 24);
        daysLeft = Math.max(0, 7 - Math.ceil(daysPassed)); // 7 Days Trial
        progressPercent = ((7 - daysLeft) / 7) * 100;
    }

    const notificationOptions = [1, 2, 3, 4, 5, 6, 8, 10, 12, 24, 48];

    return (
        <div className="max-w-4xl mx-auto pb-20">
            <h1 className="text-3xl font-bold text-white mb-6">{t('settings.title')}</h1>

            <div className="space-y-6">

                {/* Subscription Status */}
                <div className={`p-6 rounded-xl shadow-lg border-s-4 ${subscriptionStatus === 'active' ? 'bg-[#1C2541] border-green-500' : 'bg-[#1C2541] border-yellow-500'}`}>
                    <h2 className="text-xl font-bold text-white mb-4 flex items-center justify-between">
                        <span>{subscriptionStatus === 'active' ? t('settings.sub_title') : t('settings.trial_title')}</span>
                        {subscriptionStatus === 'active' && (
                             <span className="bg-green-500/20 text-green-400 text-xs px-2 py-1 rounded border border-green-500/50">
                                {t('settings.active_badge')}
                             </span>
                        )}
                    </h2>

                    {subscriptionStatus === 'active' ? (
                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <p className="text-gray-400 text-xs uppercase tracking-wider">{t('settings.start_date')}</p>
                                    <p className="text-white font-medium">{startDateStr}</p>
                                </div>
                                <div>
                                    <p className="text-gray-400 text-xs uppercase tracking-wider">{t('settings.end_date')}</p>
                                    <p className="text-white font-medium">{endDateStr}</p>
                                </div>
                            </div>

                            <div>
                                <div className="flex justify-between items-end mb-1">
                                    <span className="text-gray-300 text-sm">{t('settings.days_left')}</span>
                                    <span className="text-[#F7C873] font-bold text-xl">{daysLeft}</span>
                                </div>
                                <div className="w-full h-2 bg-gray-700 rounded-full overflow-hidden">
                                    <div 
                                        className="h-full bg-gradient-to-r from-green-500 to-[#F7C873]" 
                                        style={{ width: `${progressPercent}%` }}
                                    ></div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div>
                             <div className="flex items-center justify-between mb-2">
                                <span className="text-gray-300">{t('settings.days_remaining')}</span>
                                <span className={`text-2xl font-bold ${daysLeft > 0 ? 'text-[#F7C873]' : 'text-red-500'}`}>
                                    {daysLeft} {language === 'ar' ? 'أيام' : 'Days'}
                                </span>
                            </div>
                            <p className="text-xs text-gray-500 mb-4">
                                {t('settings.trial_desc')}
                            </p>

                            <button 
                                onClick={() => setShowActivateModal(true)}
                                className="w-full bg-[#F7C873] text-[#0B132B] font-bold py-2 px-4 rounded-lg hover:bg-yellow-400 transition-colors shadow-md"
                            >
                                {t('settings.activate_now')}
                            </button>
                        </div>
                    )}
                </div>

                {/* Notification Settings */}
                <div className="bg-[#1C2541] p-6 rounded-xl shadow-lg border-s-4 border-purple-500">
                    <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                        </svg>
                        {t('settings.notification_title')}
                    </h2>
                    <div>
                        <label className="block text-gray-400 text-sm mb-2">{t('settings.notification_lead_time')}</label>
                        <div className="flex items-center gap-2">
                            <select
                                value={notifyLeadTime}
                                onChange={(e) => onSetNotifyLeadTime(Number(e.target.value))}
                                className="bg-[#0B132B] border border-gray-600 text-white rounded-md p-3 focus:ring-[#F7C873] focus:border-[#F7C873] cursor-pointer min-w-[120px]"
                            >
                                {notificationOptions.map(hours => (
                                    <option key={hours} value={hours}>
                                        {hours} {t('settings.hours')}
                                    </option>
                                ))}
                            </select>
                        </div>
                        <p className="text-xs text-gray-500 mt-2">{t('settings.notification_desc')}</p>
                    </div>
                </div>

                {/* Language Settings */}
                <div className="bg-[#1C2541] p-6 rounded-xl shadow-lg border-s-4 border-[#F7C873]">
                    <h2 className="text-xl font-bold text-white mb-4 flex items-center">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 me-2 text-[#F7C873]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5h12M9 3v2m4.25 16l-4.25-4.25M19.5 19.5l-4.25-4.25M19.5 19.5h-4.25M19.5 19.5v-4.25" />
                        </svg>
                        {t('settings.language_title')}
                    </h2>
                    <div className="flex gap-4">
                        <button 
                            onClick={() => setLanguage('ar')}
                            className={`flex-1 py-3 px-4 rounded-lg font-bold transition-all ${language === 'ar' ? 'bg-[#F7C873] text-[#0B132B]' : 'bg-[#0B132B] text-gray-400 hover:text-white'}`}
                        >
                            العربية
                        </button>
                        <button 
                            onClick={() => setLanguage('en')}
                            className={`flex-1 py-3 px-4 rounded-lg font-bold transition-all ${language === 'en' ? 'bg-[#F7C873] text-[#0B132B]' : 'bg-[#0B132B] text-gray-400 hover:text-white'}`}
                        >
                            English
                        </button>
                    </div>
                </div>

                {/* Monthly Revenue History */}
                <div className="bg-[#1C2541] p-6 rounded-xl shadow-lg border-s-4 border-green-400">
                    <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                        </svg>
                        {t('dashboard.monthly_revenue_history')}
                    </h2>
                    <div className="overflow-x-auto max-h-60 overflow-y-auto custom-scrollbar">
                        <table className="w-full text-start">
                            <thead className="bg-[#0B132B] sticky top-0">
                                <tr>
                                    <th className="p-3 text-start text-gray-400 text-sm">{t('dashboard.month')}</th>
                                    <th className="p-3 text-start text-gray-400 text-sm">{t('dashboard.revenue')}</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700">
                                {monthlyRevenueHistory.length > 0 ? (
                                    monthlyRevenueHistory.map((item, index) => (
                                        <tr key={index} className="hover:bg-[#2A3450] transition-colors">
                                            <td className="p-3 text-white font-medium">
                                                {item.date.toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', { month: 'long', year: 'numeric' })}
                                            </td>
                                            <td className="p-3 text-green-400 font-bold">
                                                {formatCurrency(item.amount)}
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <td colSpan={2} className="p-4 text-center text-gray-500 text-sm">
                                            {t('dashboard.no_revenue_data')}
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Backup & Restore */}
                <div className="bg-[#1C2541] p-6 rounded-xl shadow-lg border-s-4 border-blue-400">
                    <h2 className="text-xl font-bold text-white mb-4 flex items-center">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 me-2 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
                        </svg>
                        {t('settings.backup_restore')}
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="bg-[#0B132B] p-4 rounded-lg">
                            <h3 className="font-semibold text-white mb-2">{t('settings.export')}</h3>
                            <p className="text-sm text-gray-400 mb-4 h-12">{t('settings.export_desc')}</p>
                            <button 
                                onClick={handleExport}
                                className="w-full bg-[#F7C873] text-[#0B132B] font-bold py-2 px-4 rounded-lg hover:bg-yellow-400 transition-colors"
                            >
                                {t('settings.export')}
                            </button>
                        </div>

